function calculateParkingFee(
  duration: number,
  day: string,
  vehicleType: string,
  lostTicket: boolean
): number {
  if (lostTicket) return 45.00;

  let baseFee = 0.00;
  if (duration > 15) {
    const hoursCharged = Math.ceil((duration - 15) / 60);
    baseFee = hoursCharged * 3.50;
  }

  let fee = baseFee;
  if (vehicleType === "electric") {
    fee = baseFee * 0.80;
    fee = Math.round(fee * 4) / 4;
  }

  const cap = day === "Saturday" || day === "Sunday" ? 18.00 : 24.00;
  fee = Math.min(fee, cap);

  return Math.round(fee * 100) / 100;
}

function calculateParkingFee(
  durationMinutes: number,
  dayOfWeek: string,
  vehicleType: string,
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  const isWeekend = dayOfWeek === "Saturday" || dayOfWeek === "Sunday";

  if (durationMinutes <= 15) {
    return 0.0;
  }

  const durationHours = Math.ceil((durationMinutes - 15) / 60);
  let fee = durationHours * 3.5;

  if (vehicleType === "Electric") {
    fee = fee * 0.8;
    fee = Math.round(fee * 4) / 4;
  }

  const maxFee = isWeekend ? 18 : 24;
  fee = Math.min(fee, maxFee);

  return Math.round(fee * 100) / 100;
}

const testCases = [
  { duration: 10, day: "Monday", vehicle: "Standard", lost: false, expected: 0.0 },
  { duration: 30, day: "Monday", vehicle: "Standard", lost: false, expected: 3.5 },
  { duration: 90, day: "Monday", vehicle: "Standard", lost: false, expected: 10.5 },
  { duration: 300, day: "Monday", vehicle: "Standard", lost: false, expected: 24.0 },
  { duration: 300, day: "Saturday", vehicle: "Standard", lost: false, expected: 18.0 },
  { duration: 90, day: "Monday", vehicle: "Electric", lost: false, expected: 8.25 },
  { duration: 50, day: "Monday", vehicle: "Electric", lost: false, expected: 2.75 },
  { duration: 100, day: "Friday", vehicle: "Electric", lost: false, expected: 13.95 },
  { duration: 999, day: "Monday", vehicle: "Standard", lost: true, expected: 45.0 },
  { duration: 50, day: "Sunday", vehicle: "Electric", lost: false, expected: 2.75 },
];

testCases.forEach((test) => {
  const result = calculateParkingFee(
    test.duration,
    test.day,
    test.vehicle,
    test.lost
  );
  const pass = Math.abs(result - test.expected) < 0.01;
  console.log(
    `${pass ? "✓" : "✗"} Duration: ${test.duration}m, Day: ${test.day}, Vehicle: ${test.vehicle}, Lost: ${test.lost} => $${result.toFixed(2)} (expected $${test.expected.toFixed(2)})`
  );
});

function calculateParkingFee(
  durationMinutes: number,
  day: string,
  vehicleType: string,
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  if (durationMinutes <= 15) {
    return 0.0;
  }

  const additionalMinutes = durationMinutes - 15;
  const additionalHours = Math.ceil(additionalMinutes / 60);
  let fee = additionalHours * 3.5;

  if (vehicleType === "electric") {
    fee = fee * 0.8;
  }

  const isWeekend = day === "Saturday" || day === "Sunday";
  const maxFee = isWeekend ? 18 : 24;
  fee = Math.min(fee, maxFee);

  fee = Math.round(fee * 4) / 4;

  return Math.round(fee * 100) / 100;
}

const testCases = [
  { durationMinutes: 10, day: "Monday", vehicleType: "sedan", isLostTicket: false, expected: 0.0 },
  { durationMinutes: 15, day: "Monday", vehicleType: "sedan", isLostTicket: false, expected: 0.0 },
  { durationMinutes: 16, day: "Monday", vehicleType: "sedan", isLostTicket: false, expected: 3.5 },
  { durationMinutes: 60, day: "Monday", vehicleType: "sedan", isLostTicket: false, expected: 7.0 },
  { durationMinutes: 60, day: "Monday", vehicleType: "electric", isLostTicket: false, expected: 5.6 },
  { durationMinutes: 480, day: "Monday", vehicleType: "sedan", isLostTicket: false, expected: 24.0 },
  { durationMinutes: 480, day: "Saturday", vehicleType: "sedan", isLostTicket: false, expected: 18.0 },
  { durationMinutes: 60, day: "Monday", vehicleType: "sedan", isLostTicket: true, expected: 45.0 },
  { durationMinutes: 60, day: "Saturday", vehicleType: "electric", isLostTicket: false, expected: 5.6 },
];

testCases.forEach((testCase) => {
  const result = calculateParkingFee(
    testCase.durationMinutes,
    testCase.day,
    testCase.vehicleType,
    testCase.isLostTicket
  );
  const passed = Math.abs(result - testCase.expected) < 0.01;
  console.log(
    `${passed ? "✓" : "✗"} Duration: ${testCase.durationMinutes}min, Day: ${testCase.day}, Vehicle: ${testCase.vehicleType}, Lost: ${testCase.isLostTicket} => ${result} (expected ${testCase.expected})`
  );
});

function calculateParkingFee(
  durationMinutes: number,
  dayOfWeek: string,
  vehicleType: string,
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  if (durationMinutes < 15) {
    return 0.0;
  }

  const chargeableMinutes = durationMinutes - 15;
  const hours = Math.ceil(chargeableMinutes / 60);
  let fee = hours * 3.5;

  if (vehicleType === "electric") {
    fee *= 0.8;
  }

  const isWeekend = dayOfWeek === "Saturday" || dayOfWeek === "Sunday";
  const maxFee = isWeekend ? 18 : 24;

  fee = Math.min(fee, maxFee);

  fee = Math.round(fee * 4) / 4;
  fee = Math.round(fee * 100) / 100;

  return fee;
}

const testCases = [
  {
    name: "Free parking under 15 minutes",
    durationMinutes: 10,
    dayOfWeek: "Monday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 0.0,
  },
  {
    name: "First chargeable minute (15-75 min)",
    durationMinutes: 16,
    dayOfWeek: "Monday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 3.5,
  },
  {
    name: "Hourly escalation (1h 1min)",
    durationMinutes: 61,
    dayOfWeek: "Monday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 7.0,
  },
  {
    name: "Electric vehicle discount",
    durationMinutes: 75,
    dayOfWeek: "Monday",
    vehicleType: "electric",
    isLostTicket: false,
    expected: 5.6,
  },
  {
    name: "Weekend rate cap",
    durationMinutes: 360,
    dayOfWeek: "Saturday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 18.0,
  },
  {
    name: "Weekday rate cap",
    durationMinutes: 480,
    dayOfWeek: "Monday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 24.0,
  },
  {
    name: "Lost ticket flat fee",
    durationMinutes: 120,
    dayOfWeek: "Monday",
    vehicleType: "sedan",
    isLostTicket: true,
    expected: 45.0,
  },
  {
    name: "Combined electric + weekend",
    durationMinutes: 120,
    dayOfWeek: "Sunday",
    vehicleType: "electric",
    isLostTicket: false,
    expected: 14.0,
  },
  {
    name: "Rounding to nearest quarter then cent",
    durationMinutes: 100,
    dayOfWeek: "Tuesday",
    vehicleType: "sedan",
    isLostTicket: false,
    expected: 10.5,
  },
];

testCases.forEach((test) => {
  const result = calculateParkingFee(
    test.durationMinutes,
    test.dayOfWeek,
    test.vehicleType,
    test.isLostTicket
  );
  const passed = Math.abs(result - test.expected) < 0.01;
  console.log(
    `${passed ? "✓" : "✗"} ${test.name}: expected ${test.expected}, got ${result}`
  );
});
